noncompliant:
class MyClass; // Forward declaration

class MyClass { // Noncompliant - redundant forward declaration
public:
  void method();
};

// Later in file
class MyClass; // Noncompliant - already defined above

struct Point;
struct Point { int x, y; }; // Noncompliant - redundant forward declaration

compliant:
class MyClass { // Compliant - no redundant forward declaration
public:
  void method();
};

// Forward declaration only when needed
class ForwardClass; // Used before definition
void useForward(ForwardClass* ptr);

class ForwardClass { // Definition comes later
public:
  int value;
};
